#include <iostream>
#include <iomanip>

class Rectangle {
public:
    double width {};
    double height {};

    double area() const {
        return width * height;
    }

    double perimeter() const {
        return 2.0 * (width + height);
    }

    void scale(double factor) {
        width  *= factor;
        height *= factor;
    }
};

int main() {
    double w {}, h {}, factor {};
    std::cin >> w >> h >> factor;

    Rectangle r { .width = w, .height = h };
    r.scale(factor);

    std::cout << std::fixed << std::setprecision(2);
    std::cout << "Width: "     << r.width       << '\n';
    std::cout << "Height: "    << r.height      << '\n';
    std::cout << "Area: "      << r.area()      << '\n';
    std::cout << "Perimeter: " << r.perimeter() << '\n';

    return 0;
}

