exercises.solution_code:
#include <iostream>
#include <iomanip>

class TemperatureLog {
public:
    double readings[10] {};
    int count {};

    void add(double temp) {
        readings[count] = temp;
        ++count;
    }

    double minimum() const {
        double min { readings[0] };
        for (int i { 1 }; i < count; ++i)
            if (readings[i] < min)
                min = readings[i];
        return min;
    }

    double maximum() const {
        double max { readings[0] };
        for (int i { 1 }; i < count; ++i)
            if (readings[i] > max)
                max = readings[i];
        return max;
    }

    double average() const {
        double sum {};
        for (int i {}; i < count; ++i)
            sum += readings[i];
        return sum / count;
    }
};

int main() {
    int n {};
    std::cin >> n;

    TemperatureLog log {};

    for (int i {}; i < n; ++i) {
        double t {};
        std::cin >> t;
        log.add(t);
    }

    std::cout << std::fixed;
    std::cout << std::setprecision(1) << "Min: "     << log.minimum() << '\n';
    std::cout << std::setprecision(1) << "Max: "     << log.maximum() << '\n';
    std::cout << std::setprecision(2) << "Average: " << log.average() << '\n';

    return 0;
}
